    # --- Rate Limiting ---

    def check_rate_limit(self, identifier: str, max_requests: int = 100) -> Dict[str, Any]:
        """Check rate limit for an identifier (user_id, IP, API key, etc.)."""
        key = f"{KEY_PREFIX_RATE_LIMIT}{identifier}"

        try:
            pipe = self.client.pipeline()
            pipe.incr(key)
            pipe.ttl(key)
            results = pipe.execute()

            current_count = results[0]
            ttl = results[1]

            if ttl == -1:
                self.client.expire(key, RATE_LIMIT_WINDOW_TTL)
                ttl = RATE_LIMIT_WINDOW_TTL

            allowed = current_count <= max_requests
            remaining = max(0, max_requests - current_count)

            if not allowed:
                logger.warning(f"Rate limit exceeded for {identifier}: {current_count}/{max_requests}")

            return {
                "allowed": allowed,
                "limit": max_requests,
                "remaining": remaining,
                "reset_in": ttl,
                "current": current_count,
            }
        except RedisError as e:
            logger.error(f"Rate limit check failed: {e}")
            # Fail open - allow request if Redis is unavailable
            return {
                "allowed": True,
                "limit": max_requests,
                "remaining": max_requests,
                "reset_in": RATE_LIMIT_WINDOW_TTL,
                "current": 0,
                "error": "Rate limit check unavailable",
            }

