app = Flask(__name__)
redis_client: Optional[RedisClusterClient] = None


def get_redis_client() -> RedisClusterClient:
    """Get or create Redis client singleton."""
    global redis_client
    if redis_client is None:
        redis_client = RedisClusterClient()
    return redis_client


def require_service_auth(f):
    """Decorator to require service-level authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("X-Service-API-Key", "")
        if not SERVICE_API_KEY:
            logger.warning("SERVICE_API_KEY not configured - skipping service auth")
        elif not hmac.compare_digest(auth_header, SERVICE_API_KEY):
            return jsonify({"error": "Unauthorized - invalid service API key"}), 401
        return f(*args, **kwargs)
    return decorated


def require_session(f):
    """Decorator to require a valid session token."""
    @wraps(f)
    def decorated(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing or invalid Authorization header"}), 401

        token = auth_header[7:]
        rc = get_redis_client()
        session_data = rc.validate_session_token(token)

        if not session_data:
            return jsonify({"error": "Invalid or expired session token"}), 401

        g.session_data = session_data
        g.user_id = session_data.get("user_id")
        return f(*args, **kwargs)
    return decorated


def apply_rate_limit(identifier_func, max_requests=100):
    """Decorator factory for rate limiting."""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            rc = get_redis_client()
            identifier = identifier_func()
            rate_result = rc.check_rate_limit(identifier, max_requests)

            if not rate_result["allowed"]:
                response = jsonify({
                    "error": "Rate limit exceeded",
                    "retry_after": rate_result["reset_in"],
                })
                response.status_code = 429
                response.headers["X-RateLimit-Limit"] = str(rate_result["limit"])
                response.headers["X-RateLimit-Remaining"] = str(rate_result["remaining"])
                response.headers["X-RateLimit-Reset"] = str(rate_result["reset_in"])
                response.headers["Retry-After"] = str(rate_result["reset_in"])
                return response

            response = f(*args, **kwargs)
            if hasattr(response, 'headers'):
                response.headers["X-RateLimit-Limit"] = str(rate_result["limit"])
                response.headers["X-RateLimit-Remaining"] = str(rate_result["remaining"])
                response.headers["X-RateLimit-Reset"] = str(rate_result["reset_in"])
            return response
        return decorated
    return decorator


# --- Health & Status Endpoints ---

@app.route("/health", methods=["GET"])
def health():
    """Health check endpoint."""
    try:
        rc = get_redis_client()
        redis_health = rc.health_check()
        status_code = 200 if redis_health["status"] == "healthy" else 503
        return jsonify({
            "service": "cache-service",
            "status": redis_health["status"],
            "redis": redis_health,
            "timestamp": datetime.utcnow().isoformat(),
        }), status_code
    except Exception as e:
        return jsonify({
            "service": "cache-service",
            "status": "unhealthy",
            "error": str(e),
            "timestamp": datetime.utcnow().isoformat(),
        }), 503


