    if not data or "token" not in data:
        return jsonify({"error": "token is required"}), 400

    rc = get_redis_client()
    session_data = rc.validate_session_token(data["token"])

    if session_data:
        return jsonify({
            "valid": True,
            "session": session_data,
        }), 200
    else:
        return jsonify({
            "valid": False,
        }), 200


