# --- Rate Limit Check Endpoint ---

@app.route("/rate-limit/check", methods=["POST"])
@require_service_auth
def check_rate_limit():
    """Check rate limit for an identifier."""
    data = request.get_json()
    if not data or "identifier" not in data:
        return jsonify({"error": "identifier is required"}), 400

    max_requests = data.get("max_requests", 100)

    rc = get_redis_client()
    result = rc.check_rate_limit(data["identifier"], max_requests)

    return jsonify(result), 200


# --- Temporary Data Endpoints ---

@app.route("/temp/<key_suffix>", methods=["PUT"])
@require_service_auth
def store_temp(key_suffix):
    """Store temporary data."""
    data = request.get_json()
    if not data or "value" not in data:
        return jsonify({"error": "value is required"}), 400

    ttl = data.get("ttl", TEMP_DATA_TTL)
    # Cap TTL at 1 hour for temp data
    ttl = min(ttl, 3600)

    rc = get_redis_client()
    full_key = rc.store_temp_data(key_suffix, data["value"], ttl)

    return jsonify({
        "stored": True,
        "key": key_suffix,
        "ttl": ttl,
    }), 200


@app.route("/temp/<key_suffix>", methods=["GET"])
@require_service_auth
def get_temp(key_suffix):
    """Get temporary data."""
    rc = get_redis_client()
    value = rc.get_temp_data(key_suffix)

    if value is not None:
        return jsonify({
            "found": True,
            "value": value,
        }), 200
    else:
        return jsonify({
            "found": False,
        }), 404


