@app.route("/protected/resource", methods=["GET"])
@require_session
@apply_rate_limit(lambda: getattr(g, 'user_id', request.remote_addr), max_requests=60)
def protected_resource():
    """Example protected endpoint requiring session authentication."""
    return jsonify({
        "message": "Access granted",
        "user_id": g.user_id,
        "session": g.session_data,
    }), 200


